     5→<script lang="ts">
     6→	import { onMount, onDestroy } from 'svelte';
     7→	import { getService } from '$lib/di/Container';
     8→	import { getEventBus } from '$lib/events/EventBus';
     9→	import { plotStore } from '$lib/stores/plotStore';
    10→	import type { PlotService } from '$lib/services/PlotService';
    11→	import type {
    12→		PlotProvider,
    13→		PlotPanelState,
    14→		PlotConfig,
    15→		PlotInteraction
    16→	} from '$lib/plotting/PlotProvider';
    17→
    18→	// Props
    19→	let { panelId, className = '' }: { panelId: string; className?: string } = $props();
    20→
    21→	// Services
    22→	let plotService: PlotService | null = null;
    23→	let eventBus = getEventBus();
    24→
    25→	// State
    26→	let panelState = $state<PlotPanelState | undefined>(undefined);
    27→	let providerComponent = $state<any>(null);
    28→	let plotContainer: HTMLDivElement;
    29→	let isExporting = $state(false);
    30→
    31→	// Derived
    32→	let isLoading = $derived(panelState?.isLoading ?? false);
    33→	let hasError = $derived(!!panelState?.error);
    34→	let errorMessage = $derived(panelState?.error?.message ?? '');
    35→	let hasData = $derived((panelState?.series.length ?? 0) > 0);
    36→
    37→	// Lifecycle
    38→	onMount(async () => {
    39→		plotService = await getService<PlotService>('plotService');
    40→
    41→		// Get initial panel state
    42→		panelState = getPlotPanel(panelId);
    43→
    44→		// Subscribe to panel events
    45→		const unsubscribes = [
    46→			// Component creation
    47→			eventBus.on('plot.panel.create', async ({ panelId: id, component }) => {
    48→				if (id === panelId && component) {
    49→					await mountComponent(component);
    50→				}
    51→			}),
    52→
    53→			// Data updates
    54→			eventBus.on('plot.updated', ({ panelId: id, series }) => {
    55→				if (id === panelId) {
    56→					plotStore.updatePanelSeries(panelId, series);
    57→				}
    58→			}),
    59→
    60→			// Loading state
    61→			eventBus.on('plot.loading', ({ panelId: id, isLoading }) => {
    62→				if (id === panelId) {
    63→					plotStore.setPanelLoading(panelId, isLoading);
    64→				}
    65→			}),
    66→
    67→			// Error state
    68→			eventBus.on('plot.error', ({ panelId: id, error }) => {
    69→				if (id === panelId) {
    70→					plotStore.setPanelError(panelId, error);
    71→				}
    72→			}),
    73→
    74→			// Export events
    75→			eventBus.on('plot.export.start', ({ panelId: id }) => {
    76→				if (id === panelId) {
    77→					isExporting = true;
    78→				}
    79→			}),
    80→
    81→			eventBus.on('plot.export.complete', ({ panelId: id }) => {
    82→				if (id === panelId) {
    83→					isExporting = false;
    84→				}
    85→			})
    86→		];
    87→
    88→		// Set as active panel
    89→		plotStore.setActivePanel(panelId);
    90→
    91→		return () => {
    92→			unsubscribes.forEach((fn) => fn());
    93→
    94→			// Clean up component
    95→			if (providerComponent?.destroy) {
    96→				providerComponent.destroy();
    97→			}
    98→
    99→			// Remove from store
   100→			plotStore.removePanel(panelId);
   101→		};
   102→	});
   103→
   104→	// Reactive update for panel state
   105→	$effect(() => {
   106→		panelState = getPlotPanel(panelId);
   107→	});
   108→
   109→	// Mount provider component
   110→	async function mountComponent(ComponentClass: any) {
   111→		if (!plotContainer || !panelState) return;
   112→
   113→		try {
   114→			// Clean up existing component
   115→			if (providerComponent?.destroy) {
   116→				providerComponent.destroy();
   117→			}
   118→
   119→			// Create new component instance
   120→			providerComponent = new ComponentClass({
   121→				target: plotContainer,
   122→				props: {
   123→					series: panelState.series,
   124→					config: panelState.config,
   125→					onInteraction: handleInteraction
   126→				}
   127→			});
   128→		} catch (error) {
   129→			console.error('Failed to mount plot component:', error);
   130→			plotStore.setPanelError(panelId, error as Error);
   131→		}
   132→	}
   133→
   134→	// Handle plot interactions
   135→	function handleInteraction(interaction: PlotInteraction) {
   136→		eventBus.emit('plot.interaction', {
   137→			panelId,
   138→			...interaction
   139→		});
   140→	}
   141→
   142→	// Export functions
   143→	async function exportPlot(format: 'png' | 'svg' | 'csv' | 'json') {
   144→		if (!plotService) return;
   145→
   146→		try {
   147→			isExporting = true;
   148→			await plotService.exportPlot(panelId, format);
   149→		} catch (error) {
   150→			console.error('Export failed:', error);
   151→		} finally {
   152→			isExporting = false;
   153→		}
   154→	}
   155→
   156→	// Panel actions
   157→	function refreshPlot() {
   158→		eventBus.emit('plot.refresh', { panelId });
   159→	}
   160→
   161→	function clearPlot() {
   162→		if (panelState) {
   163→			plotStore.updatePanelSeries(panelId, []);
   164→		}
   165→	}
   166→
   167→	function closePlot() {
   168→		eventBus.emit('panel.close', { panelId });
   169→	}
   170→
   171→	// Focus handling
   172→	function handleFocus() {
   173→		plotStore.setActivePanel(panelId);
   174→	}
   175→
   176→	// Config updates
   177→	$effect(() => {
   178→		if (providerComponent && panelState?.config) {
   179→			// Update component config
   180→			providerComponent.$set({ config: panelState.config });
   181→		}
   182→	});
   183→
   184→	// Series updates
   185→	$effect(() => {
   186→		if (providerComponent && panelState?.series) {
   187→			// Update component data
   188→			providerComponent.$set({ series: panelState.series });
   189→		}
   190→	});
   191→</script>
