     1→/**
     2→ * Plot Store
     3→ * Svelte-compatible state management for plot panels and their data
     4→ */
     5→import { writable } from 'svelte/store';
     6→import type { PlotPanelState, PlotDataSeries } from '$lib/plotting/PlotProvider';
     7→
     8→export interface PlotState {
     9→	// Plot panels by ID
    10→	panels: Map<string, PlotPanelState>;
    11→
    12→	// Currently focused panel
    13→	activePanelId: string | null;
    14→
    15→	// Panel layout preferences
    16→	panelLayouts: Map<
    17→		string,
    18→		{
    19→			width: number;
    20→			height: number;
    21→			x?: number;
    22→			y?: number;
    23→			docked?: 'left' | 'right' | 'bottom';
    24→		}
    25→	>;
    26→}
    27→
    28→// Create reactive store using Svelte's writable
    29→function createPlotStore() {
    30→	const { subscribe, update, set } = writable<PlotState>({
    31→		panels: new Map(),
    32→		activePanelId: null,
    33→		panelLayouts: new Map()
    34→	});
    35→
    36→	return {
    37→		subscribe,
    38→		
    39→		// State accessors
    40→		get panels() {
    41→			let value = new Map<string, PlotPanelState>();
    42→			subscribe(state => { value = state.panels; })();
    43→			return value;
    44→		},
    45→		
    46→		get activePanelId() {
    47→			let value: string | null = null;
    48→			subscribe(state => { value = state.activePanelId; })();
    49→			return value;
    50→		},
    51→		
    52→		get panelLayouts() {
    53→			let value = new Map<string, any>();
    54→			subscribe(state => { value = state.panelLayouts; })();
    55→			return value;
    56→		},
    57→
    58→		// Actions
    59→		addPanel: (panel: PlotPanelState) => {
    60→			update(state => {
    61→				const panels = new Map(state.panels);
    62→				panels.set(panel.id, panel);
    63→				return { ...state, panels };
    64→			});
    65→		},
    66→
    67→		updatePanel: (panelId: string, updates: Partial<PlotPanelState>) => {
    68→			update(state => {
    69→				const panels = new Map(state.panels);
    70→				const existing = panels.get(panelId);
    71→				if (existing) {
    72→					panels.set(panelId, { ...existing, ...updates });
    73→				}
    74→				return { ...state, panels };
    75→			});
    76→		},
    77→
    78→		removePanel: (panelId: string) => {
    79→			update(state => {
    80→				const panels = new Map(state.panels);
    81→				panels.delete(panelId);
    82→
    83→				// Clear active panel if it was removed
    84→				const activePanelId = state.activePanelId === panelId ? null : state.activePanelId;
    85→
    86→				// Remove layout
    87→				const panelLayouts = new Map(state.panelLayouts);
    88→				panelLayouts.delete(panelId);
    89→
    90→				return { panels, activePanelId, panelLayouts };
    91→			});
    92→		},
    93→
    94→		setActivePanel: (panelId: string | null) => {
    95→			update(state => ({ ...state, activePanelId: panelId }));
    96→		},
    97→
