/**
 * Resolve a service
 */
async resolve<T>(name: string): Promise<T> {
	const service = this.services.get(name);

	if (!service) {
		throw new Error(`Service "${name}" not found`);
	}

	// Circular dependency detection
	if (this.resolving.has(name)) {
		const cyclePath = [...this.resolutionStack, name].join(' → ');
		throw new Error(`Circular dependency detected: ${cyclePath}`);
	}

	// Return existing instance if singleton
	if (service.singleton && service.instance) {
		return service.instance;
	}

	try {
		this.resolving.add(name);
		this.resolutionStack.push(name);

		// Resolve dependencies first
		const deps = await this.resolveDependencies(service.dependencies || []);

		// Create instance
		const instance = await service.factory.apply(null, deps);

		// Store singleton instance
		if (service.singleton) {
			service.instance = instance;
		}

		return instance;
	} catch (error) {
		throw error;
	} finally {
		this.resolving.delete(name);
		this.resolutionStack.pop();
	}
}

/**
 * Resolve multiple services
 */
async resolveAll<T extends any[]>(...names: string[]): Promise<T> {
	const results = await Promise.all(names.map((name) => this.resolve(name)));
	return results as T;
}

/**
 * Check if service is registered
 */
has(name: string): boolean {
	return this.services.has(name);
}

/**
 * Clear all services
 */
clear(): void {
	this.services.clear();
	this.resolving.clear();
}

/**
 * Resolve dependencies
 */
private async resolveDependencies(deps: string[]): Promise<any[]> {
	return Promise.all(deps.map((dep) => this.resolve(dep)));
}

